import { useState, useEffect } from 'react';
import { Link, useNavigate, useLocation } from 'react-router-dom';
import { motion, AnimatePresence } from 'framer-motion';
import useCartStore from '../store/useCartStore';

const Header = () => {
    const navigate = useNavigate();
    const location = useLocation();
    // Giß║ú sß╗¡ useCartStore trß║ú vß╗ü object chß╗⌐a items
    const { items } = useCartStore() || { items: [] }; 
    const [user, setUser] = useState(null);
    const [isScrolled, setIsScrolled] = useState(false);
    const [showUserMenu, setShowUserMenu] = useState(false);

    const checkUser = () => {
        const userStr = localStorage.getItem("user");
        if (userStr) {
            try {
                setUser(JSON.parse(userStr));
            } catch (e) {
                setUser(null);
            }
        } else {
            setUser(null);
        }
    };

    useEffect(() => {
        // eslint-disable-next-line react-hooks/set-state-in-effect
        checkUser();
        
        // Lß║»ng nghe sß╗▒ kiß╗çn custom tß╗½ Login.jsx ─æß╗â cß║¡p nhß║¡t ngay lß║¡p tß╗⌐c
        window.addEventListener("storage", checkUser);
        
        const handleScroll = () => {
            setIsScrolled(window.scrollY > 0);
        };
        window.addEventListener("scroll", handleScroll);

        return () => {
            window.removeEventListener("storage", checkUser);
            window.removeEventListener("scroll", handleScroll);
        };
    }, []);

    const handleLogout = () => {
        localStorage.removeItem("token");
        localStorage.removeItem("user");
        setUser(null);
        setShowUserMenu(false);
        window.dispatchEvent(new Event("storage")); // Cß║¡p nhß║¡t lß║íi trß║íng th├íi cho c├íc component kh├íc
        navigate("/login");
    };

    const isActive = (path) => location.pathname === path;

    return (
        <header className={`fixed top-0 left-0 right-0 z-50 transition-all duration-300 ${isScrolled ? 'bg-white/80 backdrop-blur-md shadow-sm py-3' : 'bg-transparent py-5'}`}>
            <div className="max-w-7xl mx-auto px-4 sm:px-6 flex items-center justify-between">
                {/* Logo */}
                <Link to="/" className="flex items-center gap-2 group">
                    <div className="w-10 h-10 bg-primary rounded-xl flex items-center justify-center text-white font-bold text-xl shadow-lg shadow-primary/30 group-hover:scale-105 transition-transform">
                        S
                    </div>
                    <span className="font-bold text-xl tracking-tight text-primary-dark">
                        STEM Shop
                    </span>
                </Link>

                {/* Navigation */}
                <nav className="hidden md:flex items-center gap-8">
                    {[
                        { name: 'Trang chß╗º', path: '/' },
                        { name: 'Sß║ún phß║⌐m', path: '/products' },
                    ].map((item) => (
                        <Link 
                            key={item.path} 
                            to={item.path}
                            className={`text-sm font-medium transition-colors ${
                                isActive(item.path) 
                                    ? 'text-primary' 
                                    : 'text-gray-500 hover:text-primary'
                            }`}
                        >
                            {item.name}
                        </Link>
                    ))}
                </nav>

                {/* Actions */}
                <div className="flex items-center gap-4">
                    {/* Cart - Hide for Admin */}
                    {(!user || user.role !== 'Admin') && (
                        <Link to="/cart" className="relative p-2 hover:bg-gray-100 rounded-full transition-colors group">
                            <svg className="w-6 h-6 text-gray-600 group-hover:text-primary transition-colors" fill="none" stroke="currentColor" viewBox="0 0 24 24">
                                <path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M16 11V7a4 4 0 00-8 0v4M5 9h14l1 12H4L5 9z" />
                            </svg>
                            {items && items.length > 0 && (
                                <span className="absolute top-0 right-0 w-5 h-5 bg-danger text-white text-xs font-bold rounded-full flex items-center justify-center border-2 border-white">
                                    {items.length}
                                </span>
                            )}
                        </Link>
                    )}

                    {/* User Section */}
                    {user ? (
                        <div className="relative">
                            <button 
                                onClick={() => setShowUserMenu(!showUserMenu)}
                                className="flex items-center gap-2 hover:bg-gray-100 py-1 px-2 rounded-lg transition-colors cursor-pointer"
                            >
                                <div className="w-8 h-8 bg-secondary/10 text-secondary rounded-full flex items-center justify-center font-bold">
                                    {user.fullName ? user.fullName.charAt(0).toUpperCase() : 'U'}
                                </div>
                                <span className="text-sm font-medium text-gray-700 hidden sm:block">
                                    {user.fullName}
                                </span>
                            </button>

                            <AnimatePresence>
                                {showUserMenu && (
                                    <motion.div
                                        initial={{ opacity: 0, y: 10 }}
                                        animate={{ opacity: 1, y: 0 }}
                                        exit={{ opacity: 0, y: 10 }}
                                        className="absolute right-0 mt-2 w-48 bg-white rounded-xl shadow-xl border border-gray-100 overflow-hidden py-1"
                                    >
                                        <div className="px-4 py-3 border-b border-gray-50">
                                            <p className="text-sm font-bold text-gray-700 truncate">{user.fullName}</p>
                                            <p className="text-xs text-gray-500 truncate">{user.email}</p>
                                        </div>
                                        
                                        <Link 
                                            to="/profile" 
                                            className="block px-4 py-2 text-sm text-gray-600 hover:bg-gray-50 hover:text-primary transition-colors"
                                            onClick={() => setShowUserMenu(false)}
                                        >
                                            Th├┤ng tin c├í nh├ón
                                        </Link>
                                        {user.role !== 'Admin' ? (
                                            <Link 
                                                to="/profile?tab=orders" 
                                                className="block px-4 py-2 text-sm text-gray-600 hover:bg-gray-50 hover:text-primary transition-colors"
                                                onClick={() => setShowUserMenu(false)}
                                            >
                                                ≡ƒôï Lß╗ïch sß╗¡ mua h├áng
                                            </Link>
                                        ) : (
                                            <Link 
                                                to="/admin" 
                                                className="block px-4 py-2 text-sm text-gray-600 hover:bg-gray-50 hover:text-primary transition-colors"
                                                onClick={() => setShowUserMenu(false)}
                                            >
                                                Trang quß║ún trß╗ï
                                            </Link>
                                        )}
                                        
                                        <button 
                                            onClick={handleLogout}
                                            className="w-full text-left px-4 py-2 text-sm text-danger hover:bg-red-50 transition-colors cursor-pointer"
                                        >
                                            ─É─âng xuß║Ñt
                                        </button>
                                    </motion.div>
                                )}
                            </AnimatePresence>
                        </div>
                    ) : (
                        <div className="flex items-center gap-2">
                            <Link to="/login" className="px-4 py-2 text-sm font-medium text-gray-600 hover:text-primary transition-colors">
                                ─É─âng nhß║¡p
                            </Link>
                            <Link 
                                to="/register" 
                                className="px-4 py-2 text-sm font-medium bg-primary text-white rounded-lg hover:bg-primary-dark hover:shadow-lg hover:shadow-primary/30 transition-all"
                            >
                                ─É─âng k├╜
                            </Link>
                        </div>
                    )}
                </div>
            </div>
        </header>
    );
};

export default Header;

import { useState, useEffect, useCallback } from 'react';
import { motion, AnimatePresence } from 'framer-motion';
import { productApi } from '../../api/productApi';
import { dashboardApi } from '../../api/dashboardApi';
import { orderApi } from '../../api/orderApi';
import { categoryApi } from '../../api/categoryApi';
import { brandApi } from '../../api/brandApi';
import { warehouseApi } from '../../api/warehouseApi';

const TABS = ['Tß╗òng quan', '─É╞ín h├áng', 'Sß║ún phß║⌐m', 'Danh mß╗Ñc', 'Th╞░╞íng hiß╗çu', 'Kho h├áng'];

const STATUS_COLORS = {
  Pending: 'bg-yellow-100 text-yellow-700',
  Confirmed: 'bg-purple-100 text-purple-700',
  Shipping: 'bg-blue-100 text-blue-600',
  Done: 'bg-green-100 text-green-700',
  Cancelled: 'bg-red-100 text-red-600',
};

/* ===================== TOAST HOOK ===================== */
function useToast() {
  const [toasts, setToasts] = useState([]);
  const toast = useCallback((msg, type = 'success') => {
    const id = Date.now();
    setToasts(prev => [...prev, { id, msg, type }]);
    setTimeout(() => setToasts(prev => prev.filter(t => t.id !== id)), 3500);
  }, []);
  return { toasts, toast };
}

function ToastContainer({ toasts }) {
  return (
    <div className="fixed bottom-6 right-6 z-[9999] flex flex-col gap-2">
      <AnimatePresence>
        {toasts.map(t => (
          <motion.div key={t.id}
            initial={{ opacity: 0, x: 60 }} animate={{ opacity: 1, x: 0 }} exit={{ opacity: 0, x: 60 }}
            className={`flex items-center gap-3 px-5 py-3 rounded-xl shadow-xl text-white text-sm font-medium ${
              t.type === 'error' ? 'bg-red-500' : t.type === 'warning' ? 'bg-amber-500' : 'bg-emerald-500'
            }`}>
            <span>{t.type === 'error' ? 'Γ¥î' : t.type === 'warning' ? 'ΓÜá∩╕Å' : 'Γ£à'}</span>
            {t.msg}
          </motion.div>
        ))}
      </AnimatePresence>
    </div>
  );
}

export default function Dashboard() {
  const [tab, setTab] = useState('Tß╗òng quan');
  const [products, setProducts] = useState([]);
  const [orders, setOrders] = useState([]);
  const [categories, setCategories] = useState([]);
  const [brands, setBrands] = useState([]);
  const [warehouses, setWarehouses] = useState([]);
  const [loading, setLoading] = useState(false);
  const [stats, setStats] = useState([
    { label: 'Doanh thu', value: '0─æ', color: 'bg-blue-50 text-blue-600' },
    { label: '─É╞ín h├áng', value: '0', color: 'bg-emerald-50 text-emerald-600' },
    { label: 'Sß║ún phß║⌐m', value: '0', color: 'bg-violet-50 text-violet-600' },
    { label: 'Kh├ích h├áng', value: '0', color: 'bg-amber-50 text-amber-600' },
  ]);
  const { toasts, toast } = useToast();

  // Modal states
  const [showProductModal, setShowProductModal] = useState(false);
  const [editProduct, setEditProduct] = useState(null);
  const [showCategoryModal, setShowCategoryModal] = useState(false);
  const [editCategory, setEditCategory] = useState(null);
  const [showBrandModal, setShowBrandModal] = useState(false);
  const [editBrand, setEditBrand] = useState(null);
  const [showWarehouseModal, setShowWarehouseModal] = useState(false);
  const [showImportModal, setShowImportModal] = useState(false);
  const [loadingAction, setLoadingAction] = useState(false);
  const formatPrice = (price) => new Intl.NumberFormat('vi-VN').format(price) + '─æ';
  const formatDate = (dateStr) => dateStr ? new Date(dateStr).toLocaleDateString('vi-VN') : '';

  useEffect(() => {
    const fetchData = async () => {
      setLoading(true);
      try {
        if (tab === 'Tß╗òng quan') {
          const [data, ordRes] = await Promise.all([
            dashboardApi.getStats().catch(() => ({})),
            orderApi.getAll().catch(() => ({ success: false, data: [] }))
          ]);
          setStats([
            { label: 'Doanh thu', value: formatPrice(data.totalRevenue || 0), color: 'bg-blue-50 text-blue-600' },
            { label: '─É╞ín h├áng', value: (data.totalOrders || 0).toString(), color: 'bg-emerald-50 text-emerald-600' },
            { label: 'Sß║ún phß║⌐m', value: (data.totalProducts || 0).toString(), color: 'bg-violet-50 text-violet-600' },
            { label: 'Kh├ích h├áng', value: (data.totalUsers || 0).toString(), color: 'bg-amber-50 text-amber-600' },
          ]);
          if (ordRes.success) setOrders(ordRes.data.slice(0, 5));
        } else if (tab === '─É╞ín h├áng') {
          const res = await orderApi.getAll();
          if (res.success) setOrders(res.data);
        } else if (tab === 'Sß║ún phß║⌐m') {
          await loadProducts();
        } else if (tab === 'Danh mß╗Ñc') {
          await loadCategories();
        } else if (tab === 'Th╞░╞íng hiß╗çu') {
          await loadBrands();
        } else if (tab === 'Kho h├áng') {
          await loadWarehouses();
        }
      } catch (err) {
        toast('Kh├┤ng thß╗â kß║┐t nß╗æi server. Vui l├▓ng kiß╗âm tra backend!', 'error');
      } finally {
        setLoading(false);
      }
    };
    fetchData();
    // eslint-disable-next-line react-hooks/exhaustive-deps
  }, [tab]);

  const loadProducts = async () => { const res = await productApi.getAll(); if (res.success) setProducts(res.data); };
  const loadCategories = async () => { const res = await categoryApi.getAll(); if (res.success) setCategories(res.data); };
  const loadBrands = async () => { const res = await brandApi.getAll(); if (res.success) setBrands(res.data); };
  const loadWarehouses = async () => { const data = await warehouseApi.getAll(); setWarehouses(data || []); };
  const forceRefresh = useCallback(() => {
    const cur = tab;
    setTab('__temp');
    setTimeout(() => setTab(cur), 0);
  }, [tab]);

  const handleStatusChange = async (orderId, newStatus) => {
    try {
      const res = await orderApi.updateStatus(orderId, { status: newStatus });
      if (res.success) {
        setOrders(orders.map(o => o.id === orderId ? { ...o, status: newStatus } : o));
        toast(`─É╞ín #${orderId}: ─æß╗òi trß║íng th├íi ΓåÆ ${newStatus}`, newStatus === 'Cancelled' ? 'warning' : 'success');
      } else { toast(res.message || 'Lß╗ùi cß║¡p nhß║¡t', 'error'); }
    } catch (error) { toast(error.message || 'Lß╗ùi cß║¡p nhß║¡t', 'error'); }
  };

  const handleDeleteProduct = async (id) => {
    if (!window.confirm('X├│a sß║ún phß║⌐m n├áy?')) return;
    try {
      const res = await productApi.delete(id);
      if (res.success) { loadProducts(); toast('X├│a sß║ún phß║⌐m th├ánh c├┤ng!'); }
      else toast(res.message || 'Lß╗ùi x├│a', 'error');
    } catch (error) { toast(error.message || 'Lß╗ùi x├│a sß║ún phß║⌐m', 'error'); }
  };

  const handleDeleteCategory = async (id) => {
    if (!window.confirm('X├│a danh mß╗Ñc n├áy?')) return;
    try {
      const res = await categoryApi.delete(id);
      if (res.success) { loadCategories(); toast('X├│a danh mß╗Ñc th├ánh c├┤ng!'); }
      else toast(res.message || 'Lß╗ùi x├│a', 'error');
    } catch (error) { toast(error.message || 'Lß╗ùi x├│a danh mß╗Ñc', 'error'); }
  };

  const handleDeleteBrand = async (id) => {
    if (!window.confirm('X├│a th╞░╞íng hiß╗çu n├áy?')) return;
    try {
      const res = await brandApi.delete(id);
      if (res.success) { loadBrands(); toast('X├│a th╞░╞íng hiß╗çu th├ánh c├┤ng!'); }
      else toast(res.message || 'Lß╗ùi x├│a', 'error');
    } catch (error) { toast(error.message || 'Lß╗ùi x├│a th╞░╞íng hiß╗çu', 'error'); }
  };

  const handleSaveCategory = async (e) => {
    e.preventDefault();
    setLoadingAction(true);
    const formData = new FormData(e.target);
    const data = Object.fromEntries(formData.entries());
    try {
      const res = editCategory ? await categoryApi.update(editCategory.id, data) : await categoryApi.create(data);
      if (res.success) { setShowCategoryModal(false); loadCategories(); toast(editCategory ? 'Cß║¡p nhß║¡t danh mß╗Ñc th├ánh c├┤ng!' : 'Th├¬m danh mß╗Ñc th├ánh c├┤ng!'); }
      else toast(res.message || 'Lß╗ùi l╞░u danh mß╗Ñc', 'error');
    } catch (error) { toast(error.message || 'Lß╗ùi l╞░u danh mß╗Ñc', 'error'); }
    finally { setLoadingAction(false); }
  };

  const handleSaveBrand = async (e) => {
    e.preventDefault();
    setLoadingAction(true);
    const formData = new FormData(e.target);
    const data = Object.fromEntries(formData.entries());
    try {
      const res = editBrand ? await brandApi.update(editBrand.id, data) : await brandApi.create(data);
      if (res.success) { setShowBrandModal(false); loadBrands(); toast(editBrand ? 'Cß║¡p nhß║¡t th╞░╞íng hiß╗çu th├ánh c├┤ng!' : 'Th├¬m th╞░╞íng hiß╗çu th├ánh c├┤ng!'); }
      else toast(res.message || 'Lß╗ùi l╞░u th╞░╞íng hiß╗çu', 'error');
    } catch (error) { toast(error.message || 'Lß╗ùi l╞░u th╞░╞íng hiß╗çu', 'error'); }
    finally { setLoadingAction(false); }
  };

  const handleCreateWarehouse = async (e) => {
    e.preventDefault();
    setLoadingAction(true);
    const formData = new FormData(e.target);
    const data = Object.fromEntries(formData.entries());
    try {
      await warehouseApi.create(data);
      setShowWarehouseModal(false); loadWarehouses(); toast('Tß║ío kho h├áng th├ánh c├┤ng! ≡ƒÅ¡');
    } catch (error) { toast(error.message || 'Lß╗ùi tß║ío kho', 'error'); }
    finally { setLoadingAction(false); }
  };

  const handleImportStock = async (e) => {
    e.preventDefault();
    setLoadingAction(true);
    const formData = new FormData(e.target);
    const data = Object.fromEntries(formData.entries());
    data.quantity = parseInt(data.quantity);
    try {
      await warehouseApi.importStock(data);
      setShowImportModal(false); loadWarehouses(); loadProducts(); toast(`Nhß║¡p ${data.quantity} sß║ún phß║⌐m v├áo kho th├ánh c├┤ng! ≡ƒôª`);
    } catch (error) { toast(error.message || 'Lß╗ùi nhß║¡p h├áng', 'error'); }
    finally { setLoadingAction(false); }
  };
  return (
    <div className="pt-24 pb-16 min-h-screen bg-surface">
      <ToastContainer toasts={toasts} />
      <div className="max-w-7xl mx-auto px-4 sm:px-6">
        <motion.div initial={{ opacity: 0, y: 30 }} animate={{ opacity: 1, y: 0 }} transition={{ duration: 0.6 }} className="mb-8 flex items-center justify-between">
          <div>
            <h1 className="text-3xl sm:text-4xl font-bold text-primary-dark">Admin Dashboard</h1>
            <p className="text-gray-400 mt-1">Quß║ún l├╜ cß╗¡a h├áng STEM Shop</p>
          </div>
          <button onClick={forceRefresh} className="flex items-center gap-2 px-4 py-2 bg-white rounded-xl shadow text-sm text-gray-500 hover:text-primary hover:shadow-md transition-all cursor-pointer">
            <span className={loading ? 'animate-spin' : ''}>&#8635;</span> L├ám mß╗¢i
          </button>
        </motion.div>

        {/* Tabs */}
        <div className="flex gap-1 bg-white rounded-xl p-1 shadow-sm mb-8 w-fit flex-wrap">
          {TABS.map((t) => (
            <button key={t} onClick={() => setTab(t)}
              className={`px-5 py-2.5 rounded-lg text-sm font-medium transition-all duration-300 cursor-pointer ${tab === t ? 'bg-primary text-white shadow-md' : 'text-gray-500 hover:text-primary'}`}>
              {t}
            </button>
          ))}
        </div>

        <AnimatePresence mode="wait">
          {loading && (
            <motion.div key="loader" initial={{ opacity: 0 }} animate={{ opacity: 1 }} exit={{ opacity: 0 }}
              className="flex items-center justify-center py-20 text-primary">
              <svg className="animate-spin h-8 w-8" viewBox="0 0 24 24" fill="none">
                <circle className="opacity-25" cx="12" cy="12" r="10" stroke="currentColor" strokeWidth="4"/>
                <path className="opacity-75" fill="currentColor" d="M4 12a8 8 0 018-8V0C5.373 0 0 5.373 0 12h4z"/>
              </svg>
            </motion.div>
          )}
        </AnimatePresence>

        <AnimatePresence mode="wait">
          {/* ========== Tß╗öNG QUAN ========== */}
          {tab === 'Tß╗òng quan' && (
            <motion.div key="overview" initial={{ opacity: 0, y: 20 }} animate={{ opacity: 1, y: 0 }} exit={{ opacity: 0, y: -20 }} transition={{ duration: 0.4 }}>
              <div className="grid grid-cols-1 sm:grid-cols-2 lg:grid-cols-4 gap-6 mb-8">
                {stats.map((stat, i) => (
                  <motion.div key={stat.label} initial={{ opacity: 0, y: 20 }} animate={{ opacity: 1, y: 0 }} transition={{ delay: i * 0.1 }} className="card p-6">
                    <p className="text-sm text-gray-400 mb-1">{stat.label}</p>
                    <p className="text-2xl font-bold text-primary-dark">{stat.value}</p>
                  </motion.div>
                ))}
              </div>
              <div className="card overflow-hidden">
                <div className="p-6 border-b border-gray-100"><h3 className="font-bold text-primary-dark">─É╞ín h├áng gß║ºn ─æ├óy</h3></div>
                <div className="overflow-x-auto">
                  <table className="w-full">
                    <thead><tr className="bg-gray-50">
                      <th className="text-left px-6 py-3 text-xs font-semibold text-gray-400 uppercase">ID</th>
                      <th className="text-left px-6 py-3 text-xs font-semibold text-gray-400 uppercase">Kh├ích h├áng</th>
                      <th className="text-left px-6 py-3 text-xs font-semibold text-gray-400 uppercase">Tß╗òng tiß╗ün</th>
                      <th className="text-left px-6 py-3 text-xs font-semibold text-gray-400 uppercase">Trß║íng th├íi</th>
                      <th className="text-left px-6 py-3 text-xs font-semibold text-gray-400 uppercase">Ng├áy</th>
                    </tr></thead>
                    <tbody className="divide-y divide-gray-50">
                      {orders.map((order) => (
                        <tr key={order.id} className="hover:bg-gray-50/50 transition-colors">
                          <td className="px-6 py-4 text-sm font-medium text-primary-dark">#{order.id}</td>
                          <td className="px-6 py-4 text-sm text-gray-600">User #{order.userId}</td>
                          <td className="px-6 py-4 text-sm font-medium">{formatPrice(order.totalAmount)}</td>
                          <td className="px-6 py-4"><span className={`text-xs font-semibold px-3 py-1 rounded-full ${STATUS_COLORS[order.status] || 'bg-gray-100 text-gray-600'}`}>{order.status}</span></td>
                          <td className="px-6 py-4 text-sm text-gray-400">{formatDate(order.orderDate)}</td>
                        </tr>
                      ))}
                    </tbody>
                  </table>
                </div>
              </div>
            </motion.div>
          )}

          {/* ========== ─É╞áN H├ÇNG ========== */}
          {tab === '─É╞ín h├áng' && (
            <motion.div key="orders" initial={{ opacity: 0, y: 20 }} animate={{ opacity: 1, y: 0 }} exit={{ opacity: 0, y: -20 }} transition={{ duration: 0.4 }}>
              <div className="card overflow-hidden">
                <div className="p-6 border-b border-gray-100"><h3 className="font-bold text-primary-dark">Tß║Ñt cß║ú ─æ╞ín h├áng ({orders.length})</h3></div>
                <div className="divide-y divide-gray-50">
                  {orders.map((order) => (
