            <div className="flex gap-2">
                <span className="text-gray-400 font-medium">─Éß╗ïa chß╗ë:</span>
                <span className="text-gray-700">{order.address || 'ΓÇö'}</span>
            </div>
            {order.note && (
                <div className="flex gap-2 w-full pt-1 border-t border-gray-100">
                    <span className="text-gray-400 font-medium whitespace-nowrap">Ghi ch├║:</span>
                    <span className="text-gray-600 italic">"{order.note}"</span>
                </div>
            )}
          </div>
          {order.items && order.items.length > 0 ? (
            <div className="bg-white rounded-xl border border-gray-100 overflow-hidden">
              <table className="w-full text-sm">
                <thead><tr className="bg-gray-50/80">
                  <th className="text-left px-4 py-2 text-xs text-gray-400 font-medium">Sß║ún phß║⌐m</th>
                  <th className="text-center px-4 py-2 text-xs text-gray-400 font-medium">SL</th>
                  <th className="text-right px-4 py-2 text-xs text-gray-400 font-medium">─É╞ín gi├í</th>
                  <th className="text-right px-4 py-2 text-xs text-gray-400 font-medium">Th├ánh tiß╗ün</th>
